package main

import (
	"fmt"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields provided via an "order" global object, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Create a new object to hold order fields
	obj := vm.NewObject()
	for key, value := range order {
		if err := obj.Set(key, value); err != nil {
			return 0.0, fmt.Errorf("failed to set order property '%s': %w", key, err)
		}
	}

	// Set the order object as a global variable
	vm.Set("order", obj)

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64 - handle both float64 and int64 return types
	var discount float64
	switch v := result.Export().(type) {
	case float64:
		discount = v
	case int64:
		discount = float64(v)
	default:
		return 0.0, fmt.Errorf("script must return a number (int64 or float64), got %T", v)
	}

	return discount, nil
}

